using System.Collections;
using UnityEngine;

/// <summary>
/// Inicia "challenge" via ChallengeManager.StartChallenge — activador de
/// desafio por NPC (Sistema de Missões/Desafios, Tarefa #11): usar como última
/// acção de um evento de diálogo/interacção do NPC (ex: "Aceitar Desafio") em
/// vez de (ou além de) um ChallengeTrigger no mundo.
///
/// Não faz nada se já houver um desafio activo (ChallengeManager.IsActive) ou
/// se a forma actual do jogador não puder iniciar este desafio
/// (ChallengeDefinition.IsFormAllowed) — nesse caso, usar
/// Condition_BoolVariable (ChallengeDefinition.CompletedVariable/ActiveVariable)
/// nas condições do evento para esconder/desactivar esta opção de diálogo
/// antes de chegar aqui.
///
/// A posição do jogador no momento em que esta acção corre é guardada como
/// "ponto de regresso" (usada por ChallengeDefinition.endBehavior =
/// VoltarParaEntrada).
/// </summary>
[System.Serializable]
public class Action_StartChallenge : NpcAction
{
    [Tooltip("Desafio a iniciar.")]
    public ChallengeDefinition challenge;

    public override IEnumerator Execute(NpcController npc)
    {
        if (challenge == null || ChallengeManager.Instance == null) yield break;

        var playerT = PlayerLocator.Find();
        if (playerT == null) yield break;

        var switcher = playerT.GetComponent<FormSwitcher>();
        var form = switcher != null ? switcher.CurrentForm : null;

        ChallengeManager.Instance.StartChallenge(challenge, form, playerT.position);
    }
}
